input.command:
cd /home/Axel/LeanAlgebraicGeometry-Horizon
f=$(find .archon-horizon/roadmap -name "*.yaml" -o -name "*.yml" 2>/dev/null | head); echo "files: $f"
# show picrep comments block
python3 - <<'EOF'
import glob,yaml,sys
for fn in glob.glob('.archon-horizon/roadmap/**/*.y*ml', recursive=True):
    try:
        d=yaml.safe_load(open(fn))
    except Exception as e:
        continue
    items = d.get('items') if isinstance(d,dict) else d
    if not items: continue
    for it in (items if isinstance(items,list) else items.values()):
        if isinstance(it,dict) and it.get('id')=='AJC.picrep':
            print('FILE',fn,'status',it.get('status'))
            for c in it.get('comments',[])[-3:]:
                print('--',c.get('author'),c.get('at',c.get('timestamp','')))
                print((c.get('body') or c.get('text') or '')[:400])
EOF
